import { eq, desc } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { milestones, modules, tasks } from '$lib/db/schema.js';
import type { CreateMilestoneInput, UpdateMilestoneInput } from '$lib/schemas/index.js';

// ── ID Generation ────────────────────────────────────────────────────────────

/** Get next MS-{seq} ID by querying max existing seq. */
export async function nextMilestoneId(db: BetterSQLite3Database<any>): Promise<string> {
	const rows = await db.select({ id: milestones.id }).from(milestones).all();
	let maxSeq = 0;
	for (const row of rows) {
		const seq = parseInt(row.id.replace('MS-', ''), 10);
		if (seq > maxSeq) maxSeq = seq;
	}
	return `MS-${maxSeq + 1}`;
}

// ── Create ───────────────────────────────────────────────────────────────────

export async function createMilestone(
	db: BetterSQLite3Database<any>,
	data: CreateMilestoneInput
) {
	const id = await nextMilestoneId(db);
	const result = await db
		.insert(milestones)
		.values({
			id,
			title: data.title,
			sourceMd: data.sourceMd ?? null,
			gitUrl: data.gitUrl && data.gitUrl !== '' ? data.gitUrl : null
		})
		.returning()
		.get();
	return formatMilestoneResponse(result);
}

// ── List ─────────────────────────────────────────────────────────────────────

export async function listMilestones(db: BetterSQLite3Database<any>) {
	const rows = await db.select().from(milestones).orderBy(desc(milestones.createdAt), desc(milestones.id)).all();
	return rows.map(formatMilestoneResponse);
}

// ── Get Detail ───────────────────────────────────────────────────────────────

export async function getMilestone(
	db: BetterSQLite3Database<any>,
	id: string
) {
	const milestone = await db
		.select()
		.from(milestones)
		.where(eq(milestones.id, id))
		.get();

	if (!milestone) return null;

	// Fetch modules for this milestone
	const modRows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, id))
		.all();

	// Fetch tasks for each module
	const modulesWithTasks = await Promise.all(
		modRows.map(async (mod) => {
			const taskRows = await db
				.select()
				.from(tasks)
				.where(eq(tasks.moduleId, mod.id))
				.all();
			return {
				...formatModuleResponse(mod),
				tasks: taskRows.map(formatTaskResponse)
			};
		})
	);

	return {
		...formatMilestoneResponse(milestone),
		modules: modulesWithTasks
	};
}

// ── Update ───────────────────────────────────────────────────────────────────

export async function updateMilestone(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateMilestoneInput
) {
	const existing = await db
		.select()
		.from(milestones)
		.where(eq(milestones.id, id))
		.get();

	if (!existing) return null;

	const updates: Record<string, any> = {};
	if (data.title !== undefined) updates.title = data.title;
	if (data.sourceMd !== undefined) updates.sourceMd = data.sourceMd ?? null;
	if (data.gitUrl !== undefined) updates.gitUrl = data.gitUrl === '' ? null : data.gitUrl;
	if (data.status !== undefined) updates.status = data.status;

	if (Object.keys(updates).length === 0) {
		return formatMilestoneResponse(existing);
	}

	const result = await db
		.update(milestones)
		.set(updates)
		.where(eq(milestones.id, id))
		.returning()
		.get();

	return formatMilestoneResponse(result);
}

// ── Formatters ───────────────────────────────────────────────────────────────

function formatMilestoneResponse(row: any) {
	return {
		id: row.id,
		title: row.title,
		sourceMd: row.sourceMd,
		gitUrl: row.gitUrl,
		status: row.status,
		createdAt: new Date(row.createdAt).toISOString()
	};
}

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

function formatTaskResponse(row: any) {
	return {
		id: row.id,
		shortId: row.shortId,
		moduleId: row.moduleId,
		title: row.title,
		description: row.description,
		references: row.references,
		status: row.status,
		assignee: row.assignee,
		subTotal: row.subTotal,
		subDone: row.subDone,
		progressMessage: row.progressMessage,
		commitHash: row.commitHash,
		createdAt: new Date(row.createdAt).toISOString(),
		updatedAt: new Date(row.updatedAt).toISOString(),
		reportedAt: row.reportedAt ? new Date(row.reportedAt).toISOString() : null
	};
}

export { formatModuleResponse, formatTaskResponse };

import { eq, asc } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { modules, milestones } from '$lib/db/schema.js';
import type { CreateModuleInput, UpdateModuleInput } from '$lib/schemas/index.js';

/** Body data for createModule (milestoneId comes from URL param). */
type CreateModuleBody = Omit<CreateModuleInput, 'milestoneId'>;

// ── ID Generation ────────────────────────────────────────────────────────────

/** Generate MOD-{milestone_seq}-{next_seq} ID. */
export async function nextModuleId(
	db: BetterSQLite3Database<any>,
	milestoneId: string
): Promise<string> {
	const msSeq = milestoneId.replace('MS-', '');
	const rows = await db
		.select({ id: modules.id })
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.all();
	let maxSeq = 0;
	for (const row of rows) {
		// Format: MOD-{msSeq}-{seq}
		const parts = row.id.split('-');
		const seq = parseInt(parts[parts.length - 1], 10);
		if (seq > maxSeq) maxSeq = seq;
	}
	return `MOD-${msSeq}-${maxSeq + 1}`;
}

// ── Create ───────────────────────────────────────────────────────────────────

export async function createModule(
	db: BetterSQLite3Database<any>,
	milestoneId: string,
	data: CreateModuleBody
) {
	// Verify milestone exists
	const ms = await db.select().from(milestones).where(eq(milestones.id, milestoneId)).get();
	if (!ms) return null;

	const id = await nextModuleId(db, milestoneId);
	const result = await db
		.insert(modules)
		.values({
			id,
			milestoneId,
			name: data.name,
			description: data.description ?? null,
			sortOrder: data.sortOrder ?? 0
		})
		.returning()
		.get();
	return formatModuleResponse(result);
}

// ── List by Milestone ────────────────────────────────────────────────────────

export async function listModulesByMilestone(
	db: BetterSQLite3Database<any>,
	milestoneId: string
) {
	const rows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.orderBy(asc(modules.sortOrder))
		.all();
	return rows.map(formatModuleResponse);
}

// ── Update ───────────────────────────────────────────────────────────────────

export async function updateModule(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateModuleInput
) {
	const existing = await db.select().from(modules).where(eq(modules.id, id)).get();
	if (!existing) return null;

	const updates: Record<string, any> = {};
	if (data.name !== undefined) updates.name = data.name;
	if (data.description !== undefined) updates.description = data.description ?? null;
	if (data.status !== undefined) updates.status = data.status;
	if (data.sortOrder !== undefined) updates.sortOrder = data.sortOrder;

	if (Object.keys(updates).length === 0) {
		return formatModuleResponse(existing);
	}

	const result = await db
		.update(modules)
		.set(updates)
		.where(eq(modules.id, id))
		.returning()
		.get();
	return formatModuleResponse(result);
}

// ── Formatter ────────────────────────────────────────────────────────────────

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

import { eq, asc, sql, and, inArray } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { tasks, modules, milestones } from '$lib/db/schema.js';
import type { TaskStatus } from '$lib/db/schema.js';
import type {
	ClaimTaskInput,
	ProgressTaskInput,
	CompleteTaskInput,
	AdminTaskActionInput,
	UpdateTaskInput
} from '$lib/schemas/index.js';
import { isValidTransition } from '$lib/schemas/index.js';

// ── ID Generation ────────────────────────────────────────────────────────────

/** Get next TASK-{global_seq} ID and short_id. */
export async function nextTaskId(db: BetterSQLite3Database<any>): Promise<{ id: string; shortId: number }> {
	const rows = await db.select({ id: tasks.id, shortId: tasks.shortId }).from(tasks).all();
	let maxSeq = 0;
	let maxShort = 0;
	for (const row of rows) {
		const seq = parseInt(row.id.replace('TASK-', ''), 10);
		if (seq > maxSeq) maxSeq = seq;
		if (row.shortId > maxShort) maxShort = row.shortId;
	}
	return { id: `TASK-${maxSeq + 1}`, shortId: maxShort + 1 };
}

// ── List (with filters) ─────────────────────────────────────────────────────

export interface TaskFilters {
	status?: string;
	milestoneId?: string;
	moduleId?: string;
}

export async function listTasks(
	db: BetterSQLite3Database<any>,
	filters: TaskFilters = {}
) {
	const conditions = [];
	if (filters.status) conditions.push(eq(tasks.status, filters.status as TaskStatus));
	if (filters.moduleId) conditions.push(eq(tasks.moduleId, filters.moduleId));

	// If milestoneId, join through modules
	if (filters.milestoneId) {
		const modRows = await db
			.select({ id: modules.id })
			.from(modules)
			.where(eq(modules.milestoneId, filters.milestoneId))
			.all();
		const modIds = modRows.map((m) => m.id);
		if (modIds.length === 0) return [];
		conditions.push(inArray(tasks.moduleId, modIds));
	}

	const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
	const rows = await db
		.select()
		.from(tasks)
		.where(whereClause)
		.orderBy(asc(tasks.shortId))
		.all();
	return rows.map(formatTaskResponse);
}

// ── Get Detail ───────────────────────────────────────────────────────────────

export async function getTask(
	db: BetterSQLite3Database<any>,
	id: string
) {
	const row = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!row) return null;

	// Resolve module and milestone info
	const mod = await db.select().from(modules).where(eq(modules.id, row.moduleId)).get();
	const milestone = mod
		? await db.select().from(milestones).where(eq(milestones.id, mod.milestoneId)).get()
		: null;

	return {
		...formatTaskResponse(row),
		module: mod
			? {
					id: mod.id,
					milestoneId: mod.milestoneId,
					name: mod.name,
					status: mod.status
				}
			: null,
		milestone: milestone
			? {
					id: milestone.id,
					title: milestone.title,
					status: milestone.status
				}
			: null
	};
}

// ── Claim (optimistic lock) ──────────────────────────────────────────────────

export async function claimTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: ClaimTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Only allow claiming if task is todo or in-progress
	if (existing.status !== 'todo' && existing.status !== 'in-progress') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	// Optimistic lock: if already assigned to someone else, reject
	if (existing.assignee && existing.assignee !== data.assignee) {
		return {
			error: 'conflict' as const,
			currentAssignee: existing.assignee,
			task: formatTaskResponse(existing)
		};
	}

	// Transition status if needed
	const statusUpdate =
		existing.status === 'todo' ? 'in-progress' : undefined;

	const updates: Record<string, any> = { assignee: data.assignee };
	if (statusUpdate) updates.status = statusUpdate;
	updates.updatedAt = sql`(unixepoch())`;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Progress ─────────────────────────────────────────────────────────────────

export async function progressTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: ProgressTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	if (existing.status !== 'in-progress' && existing.status !== 'todo' && existing.status !== 'blocked') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = { updatedAt: sql`(unixepoch())` };
	if (data.progressMessage !== undefined) updates.progressMessage = data.progressMessage ?? null;
	if (data.subTotal !== undefined) updates.subTotal = data.subTotal;
	if (data.subDone !== undefined) updates.subDone = data.subDone;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Complete ─────────────────────────────────────────────────────────────────

export async function completeTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: CompleteTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Must be in review or in-progress to complete
	if (existing.status !== 'review' && existing.status !== 'in-progress') {
		return { error: 'invalid_status' as const, currentStatus: existing.status };
	}

	const updates: Record<string, any> = {
		status: 'done',
		updatedAt: sql`(unixepoch())`,
		reportedAt: sql`(unixepoch())`
	};
	if (data.commitHash !== undefined) updates.commitHash = data.commitHash ?? null;
	if (data.progressMessage !== undefined) updates.progressMessage = data.progressMessage ?? null;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Admin Action ─────────────────────────────────────────────────────────────

export type AdminActionError = {
	error: 'not_found' | 'invalid_transition' | 'invalid_status';
	detail?: string;
};

export async function adminTaskAction(
	db: BetterSQLite3Database<any>,
	id: string,
	data: AdminTaskActionInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	// Admin can force any status, but validate transition for non-force actions
	// For admin actions, we allow any status change (admin override)
	const updates: Record<string, any> = {
		status: data.status,
		updatedAt: sql`(unixepoch())`
	};

	// If setting to done, also set reportedAt
	if (data.status === 'done' && !existing.reportedAt) {
		updates.reportedAt = sql`(unixepoch())`;
	}
	// If reopening from done, clear reportedAt
	if (data.status !== 'done' && existing.reportedAt) {
		updates.reportedAt = null;
	}

	if (data.progressMessage !== undefined) {
		updates.progressMessage = data.progressMessage ?? null;
	}

	// Handle assignee clearing (force release) or assignment
	if (data.assignee !== undefined) {
		updates.assignee = data.assignee ?? null;
	}

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Update task (edit properties) ───────────────────────────────────────────

export async function updateTask(
	db: BetterSQLite3Database<any>,
	id: string,
	data: UpdateTaskInput
) {
	const existing = await db.select().from(tasks).where(eq(tasks.id, id)).get();
	if (!existing) return { error: 'not_found' as const };

	const updates: Record<string, any> = { updatedAt: sql`(unixepoch())` };
	if (data.title !== undefined) updates.title = data.title;
	if (data.description !== undefined) updates.description = data.description ?? null;
	if (data.assignee !== undefined) updates.assignee = data.assignee ?? null;

	const result = await db
		.update(tasks)
		.set(updates)
		.where(eq(tasks.id, id))
		.returning()
		.get();

	return { task: formatTaskResponse(result) };
}

// ── Kanban Data (with zombie detection) ─────────────────────────────────────

const ZOMBIE_THRESHOLD_MS = 24 * 60 * 60 * 1000; // 24 hours

export async function listKanbanData(db: BetterSQLite3Database<any>, milestoneId: string) {
	// Fetch milestone
	const milestone = await db.select().from(milestones).where(eq(milestones.id, milestoneId)).get();
	if (!milestone) return null;

	// Fetch modules
	const modRows = await db
		.select()
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.orderBy(asc(modules.sortOrder))
		.all();

	const now = Date.now();

	// Fetch tasks per module with zombie flag
	const modulesWithTasks = await Promise.all(
		modRows.map(async (mod) => {
			const taskRows = await db
				.select()
				.from(tasks)
				.where(eq(tasks.moduleId, mod.id))
				.all();

			const tasksWithZombie = taskRows.map((row) => {
				const formatted = formatTaskResponse(row);
				const isZombie =
					row.status === 'in-progress' &&
					(now - new Date(row.updatedAt).getTime()) > ZOMBIE_THRESHOLD_MS;
				return { ...formatted, isZombie };
			});

			const totalTasks = tasksWithZombie.length;
			const doneTasks = tasksWithZombie.filter((t) => t.status === 'done').length;
			const progressPercent = totalTasks > 0 ? Math.round((doneTasks / totalTasks) * 100) : 0;

			// Collect unique assignees
			const assignees = [...new Set(tasksWithZombie.map((t) => t.assignee).filter(Boolean))];

			return {
				...formatModuleResponse(mod),
				tasks: tasksWithZombie,
				totalTasks,
				doneTasks,
				progressPercent,
				assignees
			};
		})
	);

	return {
		...formatMilestoneResponse(milestone),
		modules: modulesWithTasks
	};
}

// ── Formatters ───────────────────────────────────────────────────────────────

function formatMilestoneResponse(row: any) {
	return {
		id: row.id,
		title: row.title,
		sourceMd: row.sourceMd,
		gitUrl: row.gitUrl,
		status: row.status,
		createdAt: new Date(row.createdAt).toISOString()
	};
}

function formatModuleResponse(row: any) {
	return {
		id: row.id,
		milestoneId: row.milestoneId,
		name: row.name,
		description: row.description,
		status: row.status,
		sortOrder: row.sortOrder
	};
}

// ── Formatter ────────────────────────────────────────────────────────────────

function formatTaskResponse(row: any) {
	return {
		id: row.id,
		shortId: row.shortId,
		moduleId: row.moduleId,
		title: row.title,
		description: row.description,
		references: row.references,
		status: row.status,
		assignee: row.assignee,
		subTotal: row.subTotal,
		subDone: row.subDone,
		progressMessage: row.progressMessage,
		commitHash: row.commitHash,
		createdAt: new Date(row.createdAt).toISOString(),
		updatedAt: new Date(row.updatedAt).toISOString(),
		reportedAt: row.reportedAt ? new Date(row.reportedAt).toISOString() : null
	};
}

/**
 * Confirm service — atomically writes confirmed modules/tasks to DB
 * and activates the milestone (draft → in-progress).
 *
 * Pre-generates all IDs, then uses a synchronous drizzle transaction
 * (required by better-sqlite3) for atomic writes.
 */

import { eq } from 'drizzle-orm';
import type { BetterSQLite3Database } from 'drizzle-orm/better-sqlite3';
import { modules, tasks, milestones } from '$lib/db/schema.js';
import type { ConfirmModule } from '$lib/schemas/confirm.js';

// ── Types ────────────────────────────────────────────────────────────────────

export interface ConfirmResultModule {
	id: string;
	milestoneId: string;
	name: string;
	description: string | null;
	status: string;
	sortOrder: number;
	tasks: ConfirmResultTask[];
}

export interface ConfirmResultTask {
	id: string;
	shortId: number;
	moduleId: string;
	title: string;
	description: string | null;
	status: string;
}

export interface ConfirmError {
	code: 'not_found' | 'bad_request';
	message: string;
}

// ── Public API ───────────────────────────────────────────────────────────────

/**
 * Confirm a milestone's decomposed modules and tasks.
 *
 * - Validates milestone exists, is 'draft', and has sourceMd
 * - Pre-generates all IDs (async phase)
 * - Inserts all modules and tasks in a synchronous transaction
 * - Updates milestone status to 'in-progress'
 * - Returns the created structure with all generated IDs
 */
export async function confirmMilestone(
	db: BetterSQLite3Database<any>,
	milestoneId: string,
	confirmedModules: ConfirmModule[]
): Promise<{ data: ConfirmResultModule[] } | { error: ConfirmError }> {
	// 1. Validate milestone preconditions (outside transaction — read-only)
	const milestone = await db
		.select()
		.from(milestones)
		.where(eq(milestones.id, milestoneId))
		.get();

	if (!milestone) {
		return { error: { code: 'not_found', message: `Milestone ${milestoneId} not found` } };
	}

	if (milestone.status !== 'draft') {
		return {
			error: {
				code: 'bad_request',
				message: `Milestone status is '${milestone.status}', expected 'draft'`
			}
		};
	}

	if (!milestone.sourceMd) {
		return {
			error: {
				code: 'bad_request',
				message: 'Milestone has no source markdown'
			}
		};
	}

	// 2. Pre-generate all IDs (async — must happen before sync transaction)
	// We scan once for the current max, then increment in memory.
	const existingModules = await db
		.select({ id: modules.id })
		.from(modules)
		.where(eq(modules.milestoneId, milestoneId))
		.all();

	let maxModuleSeq = 0;
	for (const row of existingModules) {
		const parts = row.id.split('-');
		const seq = parseInt(parts[parts.length - 1], 10);
		if (seq > maxModuleSeq) maxModuleSeq = seq;
	}

	const existingTasks = await db.select({ id: tasks.id, shortId: tasks.shortId }).from(tasks).all();
	let maxTaskSeq = 0;
	let maxShortId = 0;
	for (const row of existingTasks) {
		const seq = parseInt(row.id.replace('TASK-', ''), 10);
		if (seq > maxTaskSeq) maxTaskSeq = seq;
		if (row.shortId > maxShortId) maxShortId = row.shortId;
	}

	// Build module entries with pre-computed IDs
	const moduleEntries: Array<{
		id: string;
		mod: ConfirmModule;
		index: number;
	}> = [];

	for (let i = 0; i < confirmedModules.length; i++) {
		maxModuleSeq++;
		moduleEntries.push({
			id: `MOD-${milestoneId.replace('MS-', '')}-${maxModuleSeq}`,
			mod: confirmedModules[i],
			index: i
		});
	}

	// Build task entries with pre-computed IDs
	const taskEntries: Array<{
		id: string;
		shortId: number;
		moduleIndex: number;
		taskIndex: number;
		title: string;
		description: string | null;
	}> = [];

	for (const entry of moduleEntries) {
		for (let t = 0; t < entry.mod.tasks.length; t++) {
			maxTaskSeq++;
			maxShortId++;
			taskEntries.push({
				id: `TASK-${maxTaskSeq}`,
				shortId: maxShortId,
				moduleIndex: entry.index,
				taskIndex: t,
				title: entry.mod.tasks[t].title,
				description: entry.mod.tasks[t].description ?? null
			});
		}
	}

	// 3. Atomic write in a synchronous transaction
	const createdModules = db.transaction((tx) => {
		const result: ConfirmResultModule[] = [];

		for (const entry of moduleEntries) {
			tx.insert(modules).values({
				id: entry.id,
				milestoneId,
				name: entry.mod.name,
				description: entry.mod.description ?? null,
				sortOrder: entry.index
			}).run();

			const modTasks = taskEntries
				.filter((te) => te.moduleIndex === entry.index)
				.map((te) => {
					tx.insert(tasks).values({
						id: te.id,
						shortId: te.shortId,
						moduleId: entry.id,
						title: te.title,
						description: te.description
					}).run();

					return {
						id: te.id,
						shortId: te.shortId,
						moduleId: entry.id,
						title: te.title,
						description: te.description,
						status: 'todo'
					};
				});

			result.push({
				id: entry.id,
				milestoneId,
				name: entry.mod.name,
				description: entry.mod.description ?? null,
				status: 'draft',
				sortOrder: entry.index,
				tasks: modTasks
			});
		}

		// Activate milestone
		tx.update(milestones)
			.set({ status: 'in-progress' })
			.where(eq(milestones.id, milestoneId))
			.run();

		return result;
	});

	const totalTasks = createdModules.reduce((sum, m) => sum + m.tasks.length, 0);
	console.info('[confirm-service] Milestone confirmed:', {
		milestoneId,
		moduleCount: createdModules.length,
		taskCount: totalTasks
	});

	return { data: createdModules };
}

import { sqliteTable, text, integer, index } from 'drizzle-orm/sqlite-core';
import { sql } from 'drizzle-orm';

// ── Status enums (stored as text in SQLite, validated by Zod at app layer) ──

export const milestoneStatusEnum = ['draft', 'in-progress', 'completed', 'archived'] as const;
export type MilestoneStatus = (typeof milestoneStatusEnum)[number];

export const moduleStatusEnum = ['draft', 'in-progress', 'completed'] as const;
export type ModuleStatus = (typeof moduleStatusEnum)[number];

export const taskStatusEnum = [
	'todo',
	'in-progress',
	'blocked',
	'review',
	'done',
	'skipped'
] as const;
export type TaskStatus = (typeof taskStatusEnum)[number];

// ── Milestone ────────────────────────────────────────────────────────────────
// Primary entity. ID format: MS-{seq} (e.g. MS-1, MS-2).

export const milestones = sqliteTable(
	'milestones',
	{
		id: text('id').primaryKey(), // MS-{seq}
		title: text('title').notNull(),
		sourceMd: text('source_md'),
		gitUrl: text('git_url'),
		status: text('status', { enum: milestoneStatusEnum }).notNull().default('draft'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`)
	},
	(table) => [index('milestone_status_idx').on(table.status)]
);

// ── Module ───────────────────────────────────────────────────────────────────
// Groups tasks within a milestone. ID format: MOD-{milestone_seq}-{seq}.

export const modules = sqliteTable(
	'modules',
	{
		id: text('id').primaryKey(), // MOD-{ms_seq}-{seq}
		milestoneId: text('milestone_id')
			.notNull()
			.references(() => milestones.id, { onDelete: 'cascade' }),
		name: text('name').notNull(),
		description: text('description'),
		status: text('status', { enum: moduleStatusEnum }).notNull().default('draft'),
		sortOrder: integer('sort_order').notNull().default(0)
	},
	(table) => [
		index('module_milestone_id_idx').on(table.milestoneId),
		index('module_status_idx').on(table.status)
	]
);

// ── Task ─────────────────────────────────────────────────────────────────────
// Atomic unit of work. ID format: TASK-{global_seq}.
// short_id is a global auto-increment for human-friendly references.

export const tasks = sqliteTable(
	'tasks',
	{
		id: text('id').primaryKey(), // TASK-{global_seq}
		shortId: integer('short_id').notNull().unique(), // global auto-increment
		moduleId: text('module_id')
			.notNull()
			.references(() => modules.id, { onDelete: 'cascade' }),
		title: text('title').notNull(),
		description: text('description'),
		references: text('references'), // JSON or text blob
		status: text('status', { enum: taskStatusEnum }).notNull().default('todo'),
		assignee: text('assignee'),
		subTotal: integer('sub_total').notNull().default(0),
		subDone: integer('sub_done').notNull().default(0),
		progressMessage: text('progress_message'),
		commitHash: text('commit_hash'),
		createdAt: integer('created_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		updatedAt: integer('updated_at', { mode: 'timestamp' })
			.notNull()
			.default(sql`(unixepoch())`),
		reportedAt: integer('reported_at', { mode: 'timestamp' })
	},
	(table) => [
		index('task_status_module_idx').on(table.status, table.moduleId),
		index('task_status_reported_idx').on(table.status, table.reportedAt),
		index('task_module_id_idx').on(table.moduleId),
		index('task_short_id_idx').on(table.shortId)
	]
);

// ── Type exports for use in application code ──

export type Milestone = typeof milestones.$inferSelect;
export type NewMilestone = typeof milestones.$inferInsert;
export type Module = typeof modules.$inferSelect;
export type NewModule = typeof modules.$inferInsert;
export type Task = typeof tasks.$inferSelect;
export type NewTask = typeof tasks.$inferInsert;

export { createMilestoneSchema, updateMilestoneSchema, milestoneResponseSchema } from './milestone.js';
export type { CreateMilestoneInput, UpdateMilestoneInput, MilestoneResponse } from './milestone.js';

export { createModuleSchema, updateModuleSchema, moduleResponseSchema } from './module.js';
export type { CreateModuleInput, UpdateModuleInput, ModuleResponse } from './module.js';

export {
	claimTaskSchema,
	progressTaskSchema,
	completeTaskSchema,
	adminTaskActionSchema,
	updateTaskSchema,
	taskResponseSchema,
	isValidTransition
} from './task.js';
export type {
	ClaimTaskInput,
	ProgressTaskInput,
	CompleteTaskInput,
	AdminTaskActionInput,
	UpdateTaskInput,
	TaskResponse
} from './task.js';

export { loginRequestSchema, loginResponseSchema } from './auth.js';
export type { LoginRequest, LoginResponse } from './auth.js';

export {
	decomposeModuleSchema,
	decomposeTaskSchema
} from './decompose.js';
export type {
	DecomposeModule,
	DecomposeTask,
	DecomposeEvent,
	DecomposeModuleEvent,
	DecomposeErrorEvent,
	DecomposeDoneEvent
} from './decompose.js';

export {
	paginationQuerySchema,
	paginatedResponseSchema,
	errorResponseSchema,
	fieldErrorSchema,
	milestoneIdSchema,
	moduleIdSchema,
	taskIdSchema,
	sourceMdSchema,
	SOURCE_MD_MAX_BYTES
} from './common.js';
export type {
	PaginationQuery,
	ErrorResponse,
	FieldError
} from './common.js';

export {
	confirmRequestSchema,
	compareRequestSchema,
	confirmModuleResponseSchema
} from './confirm.js';
export type {
	ConfirmRequest,
	ConfirmModule,
	ConfirmTask,
	CompareRequest,
	CompareEvent,
	CompareSuggestionEvent,
	CompareErrorEvent,
	CompareDoneEvent,
	ConfirmModuleResponse
} from './confirm.js';

import { z } from 'zod';
import { taskStatusEnum } from '../db/schema.js';
import { taskIdSchema, moduleIdSchema } from './common.js';

// ── Status transition map ───────────────────────────────────────────────────

const validTransitions: Record<string, string[]> = {
	todo: ['in-progress', 'skipped'],
	'in-progress': ['blocked', 'review', 'todo'],
	blocked: ['in-progress', 'todo'],
	review: ['done', 'in-progress'],
	done: [],
	skipped: []
};

export function isValidTransition(from: string, to: string): boolean {
	return validTransitions[from]?.includes(to) ?? false;
}

// ── Claim ───────────────────────────────────────────────────────────────────

export const claimTaskSchema = z.object({
	assignee: z.string().min(1, 'Assignee is required').max(100)
});
export type ClaimTaskInput = z.infer<typeof claimTaskSchema>;

// ── Progress update ─────────────────────────────────────────────────────────

export const progressTaskSchema = z.object({
	progressMessage: z.string().max(5000).optional(),
	subTotal: z.number().int().nonnegative().optional(),
	subDone: z.number().int().nonnegative().optional()
}).refine(
	(data) => {
		if (data.subTotal !== undefined && data.subDone !== undefined) {
			return data.subDone <= data.subTotal;
		}
		return true;
	},
	{ message: 'sub_done cannot exceed sub_total', path: ['subDone'] }
);
export type ProgressTaskInput = z.infer<typeof progressTaskSchema>;

// ── Complete ────────────────────────────────────────────────────────────────

export const completeTaskSchema = z.object({
	commitHash: z.string().max(40).optional(),
	progressMessage: z.string().max(5000).optional()
});
export type CompleteTaskInput = z.infer<typeof completeTaskSchema>;

// ── Admin action ────────────────────────────────────────────────────────────

export const adminTaskActionSchema = z.object({
	status: z.enum(taskStatusEnum),
	progressMessage: z.string().max(5000).optional(),
	assignee: z.string().max(100).nullable().optional()
});
export type AdminTaskActionInput = z.infer<typeof adminTaskActionSchema>;

// ── Update task (edit properties) ───────────────────────────────────────────

export const updateTaskSchema = z.object({
	title: z.string().min(1).max(300).optional(),
	description: z.string().max(10000).nullable().optional(),
	assignee: z.string().max(100).nullable().optional()
});
export type UpdateTaskInput = z.infer<typeof updateTaskSchema>;

// ── Response (with resolved references) ─────────────────────────────────────

export const taskResponseSchema = z.object({
	id: taskIdSchema,
	shortId: z.number().int().positive(),
	moduleId: moduleIdSchema,
	title: z.string(),
	description: z.string().nullable(),
	references: z.string().nullable(),
	status: z.enum(taskStatusEnum),
	assignee: z.string().nullable(),
	subTotal: z.number().int().nonnegative(),
	subDone: z.number().int().nonnegative(),
	progressMessage: z.string().nullable(),
	commitHash: z.string().nullable(),
	createdAt: z.string().datetime(),
	updatedAt: z.string().datetime(),
	reportedAt: z.string().datetime().nullable()
});
export type TaskResponse = z.infer<typeof taskResponseSchema>;

import { z } from 'zod';
import { milestoneIdSchema } from './common.js';

// ── Confirm request schema ───────────────────────────────────────────────────

/** A task within a confirmed module. */
export const confirmTaskSchema = z.object({
	title: z.string().min(1, 'Task title is required').max(500, 'Task title too long'),
	description: z.string().max(5000).optional()
});
export type ConfirmTask = z.infer<typeof confirmTaskSchema>;

/** A confirmed module with its tasks. */
export const confirmModuleSchema = z.object({
	name: z.string().min(1, 'Module name is required').max(200, 'Module name too long'),
	description: z.string().max(5000).optional(),
	tasks: z.array(confirmTaskSchema).min(1, 'Each module must have at least one task')
});
export type ConfirmModule = z.infer<typeof confirmModuleSchema>;

/** The full confirm request body. */
export const confirmRequestSchema = z.object({
	modules: z
		.array(confirmModuleSchema)
		.min(1, 'At least one module is required')
		.max(50, 'Too many modules')
});
export type ConfirmRequest = z.infer<typeof confirmRequestSchema>;

// ── Compare request schema ───────────────────────────────────────────────────

export const compareRequestSchema = z.object({
	modules: z
		.array(confirmModuleSchema)
		.min(1, 'At least one module is required')
});
export type CompareRequest = z.infer<typeof compareRequestSchema>;

// ── Confirm response types ───────────────────────────────────────────────────

export const confirmModuleResponseSchema = z.object({
	id: z.string(),
	milestoneId: z.string(),
	name: z.string(),
	description: z.string().nullable(),
	status: z.string(),
	sortOrder: z.number().int(),
	tasks: z.array(
		z.object({
			id: z.string(),
			shortId: z.number().int().positive(),
			moduleId: z.string(),
			title: z.string(),
			description: z.string().nullable(),
			status: z.string()
		})
	)
});
export type ConfirmModuleResponse = z.infer<typeof confirmModuleResponseSchema>;

// ── SSE event types for compare ──────────────────────────────────────────────

export type CompareEvent = CompareSuggestionEvent | CompareErrorEvent | CompareDoneEvent;

export interface CompareSuggestionEvent {
	type: 'suggestion';
	content: string;
}

export interface CompareErrorEvent {
	type: 'error';
	stage: 'connecting' | 'streaming';
	message: string;
}

export interface CompareDoneEvent {
	type: 'done';
}

import { describe, it, expect, beforeAll, afterAll, beforeEach } from 'vitest';
import Database from 'better-sqlite3';
import { drizzle } from 'drizzle-orm/better-sqlite3';
import { eq } from 'drizzle-orm';
import * as schema from '$lib/db/schema.js';
import { confirmMilestone } from './confirm-service.js';
import { createMilestone } from './milestone-service.js';

// ── Test database setup ──────────────────────────────────────────────────────

let db: ReturnType<typeof drizzle>;
let sqliteDb: Database.Database;

const CREATE_TABLES_SQL = `
CREATE TABLE milestones (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  source_md TEXT,
  git_url TEXT,
  status TEXT NOT NULL DEFAULT 'draft',
  created_at INTEGER NOT NULL DEFAULT (unixepoch())
);
CREATE INDEX milestone_status_idx ON milestones (status);

CREATE TABLE modules (
  id TEXT PRIMARY KEY,
  milestone_id TEXT NOT NULL REFERENCES milestones(id) ON DELETE CASCADE,
  name TEXT NOT NULL,
  description TEXT,
  status TEXT NOT NULL DEFAULT 'draft',
  sort_order INTEGER NOT NULL DEFAULT 0
);
CREATE INDEX module_milestone_id_idx ON modules (milestone_id);
CREATE INDEX module_status_idx ON modules (status);

CREATE TABLE tasks (
  id TEXT PRIMARY KEY,
  short_id INTEGER NOT NULL UNIQUE,
  module_id TEXT NOT NULL REFERENCES modules(id) ON DELETE CASCADE,
  title TEXT NOT NULL,
  description TEXT,
  "references" TEXT,
  status TEXT NOT NULL DEFAULT 'todo',
  assignee TEXT,
  sub_total INTEGER NOT NULL DEFAULT 0,
  sub_done INTEGER NOT NULL DEFAULT 0,
  progress_message TEXT,
  commit_hash TEXT,
  created_at INTEGER NOT NULL DEFAULT (unixepoch()),
  updated_at INTEGER NOT NULL DEFAULT (unixepoch()),
  reported_at INTEGER
);
CREATE INDEX task_status_module_idx ON tasks (status, module_id);
CREATE INDEX task_status_reported_idx ON tasks (status, reported_at);
CREATE INDEX task_module_id_idx ON tasks (module_id);
CREATE INDEX task_short_id_idx ON tasks (short_id);
`;

beforeAll(() => {
	sqliteDb = new Database(':memory:');
	sqliteDb.pragma('journal_mode = WAL');
	sqliteDb.pragma('foreign_keys = ON');
	sqliteDb.exec(CREATE_TABLES_SQL);
	db = drizzle(sqliteDb, { schema });
});

afterAll(() => {
	sqliteDb.close();
});

beforeEach(() => {
	sqliteDb.exec('DELETE FROM tasks');
	sqliteDb.exec('DELETE FROM modules');
	sqliteDb.exec('DELETE FROM milestones');
});

// ── Helpers ──────────────────────────────────────────────────────────────────

async function seedDraftMilestone() {
	return createMilestone(db, {
		title: 'Test Milestone',
		sourceMd: '# Requirements\n\nBuild a thing.'
	});
}

// ── Confirm service tests ────────────────────────────────────────────────────

describe('confirm-service', () => {
	it('writes modules and tasks atomically and returns IDs', async () => {
		const ms = await seedDraftMilestone();
		const result = await confirmMilestone(db, ms.id!, [
			{
				name: 'Frontend',
				description: 'UI layer',
				tasks: [
					{ title: 'Build login page', description: 'Implement OAuth flow' },
					{ title: 'Build dashboard' }
				]
			},
			{
				name: 'Backend',
				description: null,
				tasks: [{ title: 'Setup API server' }]
			}
		]);

		expect('data' in result).toBe(true);
		const modules = result.data!;
		expect(modules).toHaveLength(2);

		// Module 1
		expect(modules[0].id).toMatch(/^MOD-1-1$/);
		expect(modules[0].name).toBe('Frontend');
		expect(modules[0].description).toBe('UI layer');
		expect(modules[0].status).toBe('draft');
		expect(modules[0].sortOrder).toBe(0);
		expect(modules[0].tasks).toHaveLength(2);
		expect(modules[0].tasks[0].id).toMatch(/^TASK-\d+$/);
		expect(modules[0].tasks[0].title).toBe('Build login page');
		expect(modules[0].tasks[0].shortId).toBeGreaterThan(0);
		expect(modules[0].tasks[1].title).toBe('Build dashboard');

		// Module 2
		expect(modules[1].id).toMatch(/^MOD-1-2$/);
		expect(modules[1].name).toBe('Backend');
		expect(modules[1].description).toBeNull();
		expect(modules[1].tasks).toHaveLength(1);
		expect(modules[1].tasks[0].title).toBe('Setup API server');
	});

	it('updates milestone status from draft to in-progress', async () => {
		const ms = await seedDraftMilestone();
		await confirmMilestone(db, ms.id!, [
			{ name: 'Mod', tasks: [{ title: 'Task' }] }
		]);

		const updated = await db
			.select({ status: schema.milestones.status })
			.from(schema.milestones)
			.where(eq(schema.milestones.id, ms.id))
			.get();

		expect(updated!.status).toBe('in-progress');
	});

	it('generates correct IDs for modules and tasks', async () => {
		const ms = await seedDraftMilestone();
		const result = await confirmMilestone(db, ms.id!, [
			{ name: 'A', tasks: [{ title: 'T1' }, { title: 'T2' }] },
			{ name: 'B', tasks: [{ title: 'T3' }] }
		]);

		const modules = result.data!;
		expect(modules[0].id).toBe('MOD-1-1');
		expect(modules[1].id).toBe('MOD-1-2');
		expect(modules[0].tasks[0].id).toBe('TASK-1');
		expect(modules[0].tasks[0].shortId).toBe(1);
		expect(modules[0].tasks[1].id).toBe('TASK-2');
		expect(modules[0].tasks[1].shortId).toBe(2);
		expect(modules[1].tasks[0].id).toBe('TASK-3');
		expect(modules[1].tasks[0].shortId).toBe(3);
	});

	it('sets sortOrder based on array index', async () => {
		const ms = await seedDraftMilestone();
		const result = await confirmMilestone(db, ms.id!, [
			{ name: 'First', tasks: [{ title: 'T' }] },
			{ name: 'Second', tasks: [{ title: 'T' }] },
			{ name: 'Third', tasks: [{ title: 'T' }] }
		]);

		const modules = result.data!;
		expect(modules[0].sortOrder).toBe(0);
		expect(modules[1].sortOrder).toBe(1);
		expect(modules[2].sortOrder).toBe(2);
	});

	it('returns not_found for non-existent milestone', async () => {
		const result = await confirmMilestone(db, 'MS-999', [
			{ name: 'Mod', tasks: [{ title: 'T' }] }
		]);

		expect('error' in result).toBe(true);
		expect(result.error.code).toBe('not_found');
	});

	it('rejects non-draft milestone status', async () => {
		const ms = await seedDraftMilestone();
		// Manually set status to in-progress
		await db
			.update(schema.milestones)
			.set({ status: 'in-progress' })
			.where(eq(schema.milestones.id, ms.id));

		const result = await confirmMilestone(db, ms.id!, [
			{ name: 'Mod', tasks: [{ title: 'T' }] }
		]);

		expect('error' in result).toBe(true);
		expect(result.error.code).toBe('bad_request');
		expect(result.error.message).toContain('in-progress');
	});

	it('rejects milestone without source markdown', async () => {
		const ms = await createMilestone(db, { title: 'No Source' });

		const result = await confirmMilestone(db, ms.id!, [
			{ name: 'Mod', tasks: [{ title: 'T' }] }
		]);

		expect('error' in result).toBe(true);
		expect(result.error.code).toBe('bad_request');
		expect(result.error.message).toContain('no source markdown');
	});

	it('persists modules and tasks in the database', async () => {
		const ms = await seedDraftMilestone();
		await confirmMilestone(db, ms.id!, [
			{ name: 'Persisted', tasks: [{ title: 'Persisted Task' }] }
		]);

		const dbModules = await db
			.select()
			.from(schema.modules)
			.where(eq(schema.modules.milestoneId, ms.id))
			.all();

		expect(dbModules).toHaveLength(1);
		expect(dbModules[0].name).toBe('Persisted');

		const dbTasks = await db
			.select()
			.from(schema.tasks)
			.where(eq(schema.tasks.moduleId, dbModules[0].id))
			.all();

		expect(dbTasks).toHaveLength(1);
		expect(dbTasks[0].title).toBe('Persisted Task');
		expect(dbTasks[0].status).toBe('todo');
	});

	it('handles single module with single task', async () => {
		const ms = await seedDraftMilestone();
		const result = await confirmMilestone(db, ms.id!, [
			{ name: 'Only', tasks: [{ title: 'One' }] }
		]);

		expect(result.data!).toHaveLength(1);
		expect(result.data![0].tasks).toHaveLength(1);
	});
});

